def compute(a, b, memo=None):
    if memo is None:
        memo = {}
    if (a, b) in memo:
        return memo[(a, b)]
    if a == 0:
        result = b
    elif b == 0:
        result = a
    else:
        res1 = compute(a - 1, b, memo)
        res2 = compute(a, b - 1, memo)
        if res1 % 2 == 0:
            result = res1 + res2
        else:
            result = res1 * res2
    memo[(a, b)] = result
    return result

